import React, { useState, useEffect } from 'react';
import { contentService } from '../../services/contentService';
import MangaCard from './MangaCard';
import './PopularManga.css';

const PopularManga = () => {
  const [popularManga, setPopularManga] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('all');

  useEffect(() => {
    loadPopularManga();
  }, [activeTab]);

  const loadPopularManga = async () => {
    try {
      setLoading(true);
      const data = await contentService.getPopularContent();
      let filteredData = data;
      
      if (activeTab === 'manga') {
        filteredData = data.filter(item => item.type === 'Манга');
      } else if (activeTab === 'manhwa') {
        filteredData = data.filter(item => item.type === 'Манхва');
      }
      
      setPopularManga(filteredData);
    } catch (error) {
      console.error('Error loading popular manga:', error);
    } finally {
      setLoading(false);
    }
  };

  const tabs = [
    { id: 'all', label: 'Все', icon: 'fa-fire' },
    { id: 'manga', label: 'Манга', icon: 'fa-book' },
    { id: 'manhwa', label: 'Манхва', icon: 'fa-flag' }
  ];

  return (
    <div className="popular-manga">
      <div className="tabs">
        {tabs.map(tab => (
          <button
            key={tab.id}
            className={`tab-btn ${activeTab === tab.id ? 'active' : ''}`}
            onClick={() => setActiveTab(tab.id)}
          >
            <i className={`fas ${tab.icon}`}></i>
            {tab.label}
          </button>
        ))}
      </div>
      
      {loading ? (
        <div className="loading-grid">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="skeleton-card"></div>
          ))}
        </div>
      ) : (
        <div className="manga-grid">
          {popularManga.map(manga => (
            <MangaCard key={manga.id} manga={manga} />
          ))}
        </div>
      )}
      
      <div className="view-more">
        <button className="view-more-btn">
          Смотреть больше
          <i className="fas fa-arrow-right"></i>
        </button>
      </div>
    </div>
  );
};

export default PopularManga;
